// Preparar SMS para envío
const body = $input.first().json.body || $input.first().json;

const telefono        = body.telefono        || '';
const texto           = body.texto           || '';
const contacto_id     = body.contacto_id     || 'desconocido';
const contacto_nombre = body.contacto_nombre || 'Contacto';

if (!telefono || !texto) {
  throw new Error('Faltan campos: telefono y texto son requeridos');
}

// Limpiar texto: quitar caracteres problemáticos para SMS
const textoLimpio = texto
  .replace(/[<>"']/g, '')
  .trim()
  .substring(0, 160); // Límite SMS estándar

return [{
  json: {
    telefono,
    texto:            textoLimpio,
    contacto_id,
    contacto_nombre,
    timestamp:        new Date().toISOString(),
    hora:             new Date().toLocaleTimeString('es-CL', { hour: '2-digit', minute: '2-digit' })
  }
}];

const body = $input.first().json.body || $input.first().json;
const tipo = body.tipo || 'evento_generico';

// Mapear tipo a tabla adecuada
const tablas = {
  llamada_saliente:   'historial_llamadas',
  llamada_entrante:   'historial_llamadas',
  llamada_contestada: 'historial_llamadas',
  llamada_rechazada:  'historial_llamadas',
  llamada_finalizada: 'historial_llamadas',
  mensaje_enviado:    'mensajes',
  mensaje_recibido:   'mensajes',
  comando_voz:        'historial_comandos'
};

return [{
  json: {
    tipo,
    tabla:     tablas[tipo] || 'historial_general',
    datos:     JSON.stringify(body),
    timestamp: new Date().toISOString()
  }
}];
